query:
UPDATE chat_members
SET member_type_id = $1
WHERE member_id = $2 AND chat_id = $3 ;

-- chat_id, last_loaded_message_id, limit 
SELECT * FROM get_paginated_messages_backward (
$1,
NULLIF($2, '')::INTEGER ,
CASE WHEN '' = $3 THEN 100000 ELSE $3::INTEGER END
) ORDER BY message_id ASC;

SELECT EXISTS(
SELECT 1 FROM chats
WHERE service = 'support' AND active = TRUE AND extract(epoch from created_at) >= $1
);

INSERT INTO chat_members (chat_id, member_id, member_type_id)
VALUES ($1, $2, $3)
ON CONFLICT (member_id, chat_id) DO NOTHING;

SELECT * FROM chat_members cm
LEFT JOIN chat_member_types cmt ON cm.member_type_id = cmt.member_type_id
WHERE cm.chat_id = $1;
